#!/usr/bin/env node
import 'dotenv/config';

/**
 * IVX Holdings — GitHub Sync (Git Tree API)
 * 
 * Pushes all local files to GitHub in a single atomic commit.
 * Uses the Git Tree API for speed (1 API call vs N file-by-file calls).
 * 
 * Usage:
 *   GITHUB_TOKEN=ghp_xxx node sync-github.mjs
 *   GITHUB_TOKEN=ghp_xxx node sync-github.mjs --dry-run
 *   GITHUB_TOKEN=ghp_xxx node sync-github.mjs --message "feat: add new screen"
 */

import { readFileSync, readdirSync, statSync } from 'fs';
import { join, relative } from 'path';
import { createHash } from 'crypto';
import { getSyncPaths } from './sync-paths.mjs';

const { syncRoot: PROJECT_ROOT } = getSyncPaths(import.meta.url);

const GITHUB_TOKEN = process.env.GITHUB_TOKEN;
const BRANCH = process.env.GITHUB_BRANCH || 'main';
const API = 'https://api.github.com';

function parseGithubRepoSlug(value) {
  const normalized = String(value || '').trim();
  if (!normalized) return '';
  if (/^[^/\s]+\/[^/\s]+$/.test(normalized)) return normalized.replace(/\.git$/i, '');

import { existsSync } from 'fs';
import { dirname, join, relative, sep } from 'path';
import { fileURLToPath } from 'url';

function normalizePath(value) {
  return value.split(sep).join('/');
}

function findSyncRoot(startDir) {
  let currentDir = startDir;

  while (true) {
    if (existsSync(join(currentDir, '.git')) || existsSync(join(currentDir, 'ivx.json'))) {
      return currentDir;
    }

    const parentDir = dirname(currentDir);
    if (parentDir === currentDir) {
      return startDir;
    }

    currentDir = parentDir;
  }
}

export function getSyncPaths(importMetaUrl) {
  const scriptFile = fileURLToPath(importMetaUrl);
  const scriptDir = dirname(scriptFile);
  const envRoot = process.env.SYNC_ROOT?.trim();
  const syncRoot = envRoot && envRoot.length > 0 ? envRoot : findSyncRoot(scriptDir);
  const appRoot = existsSync(join(syncRoot, 'expo', 'package.json')) ? join(syncRoot, 'expo') : syncRoot;
  const appPrefix = appRoot === syncRoot ? '' : normalizePath(relative(syncRoot, appRoot));

  return {
    scriptFile,
    scriptDir,
    syncRoot,
    appRoot,
    appPrefix,
  };
}

export function toSyncRelativePath(syncRoot, absolutePath) {
  return normalizePath(relative(syncRoot, absolutePath));
}

